module shift_reg_8bit(
    input clk, 
    input rst, 
    input si, 
    output reg [7:0] po);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            po <= 8'b00000000;
        else
            po <= {po[6:0], si};
    end
endmodule
